prompts.content:
export default function buildPrompt(inputs: ValidatedInputs): string {
return `Raw idea: ${inputs.idea}
Industry: ${inputs.industry}
Target audience: ${inputs.audience}
Budget available: ${inputs.budget}
Timeline to launch: ${inputs.timeline}
Team size: ${inputs.team_size}
Turn this into a venture blueprint following the JSON shape defined in
your instructions.`;
}
